using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["appName"] = "ConfigMcpServer",
        ["version"] = "1.0.0",
        ["environment"] = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false,
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns the current feature flag settings.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["features"], new JsonSerializerOptions { WriteIndented = true });
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g., 'appName', 'version')")] string key)
    {
        var config = new Dictionary<string, string>
        {
            ["appName"] = "ConfigMcpServer",
            ["version"] = "1.0.0",
            ["maxRetries"] = "3",
            ["timeoutSeconds"] = "30",
        };

        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Unknown key: {key}";
    }

    [McpServerTool, Description("Returns server uptime and status information.")]
    public static string GetServerStatus()
    {
        return $"Status: Running | Uptime: {Environment.TickCount64 / 1000}s | PID: {Environment.ProcessId}";
    }
}

